DROP TABLE IF EXISTS public.page_centroids;

CREATE TABLE public.page_centroids (
    page_url TEXT PRIMARY KEY,
    centroid_embedding VECTOR(1024)
);

DO $$
DECLARE
    idx_record RECORD;
BEGIN
    FOR idx_record IN 
        SELECT indexname 
        FROM pg_indexes 
        WHERE schemaname = 'public'
          AND tablename = 'page_centroids' 
          AND indexname LIKE 'page_centroids_embedding_idx%'
    LOOP
        EXECUTE 'DROP INDEX IF EXISTS public.' || quote_ident(idx_record.indexname);
    END LOOP;
END $$;

CREATE INDEX IF NOT EXISTS page_centroids_embedding_idx 
ON public.page_centroids USING hnsw (centroid_embedding vector_cosine_ops);

BEGIN;

DROP TABLE IF EXISTS public.page_matches;

CREATE TABLE public.page_matches AS
SELECT
    a.page_url AS page_a,
    b.page_url AS page_b,
    1 - (a.centroid_embedding <=> b.centroid_embedding) AS similarity
FROM public.page_centroids a
INNER JOIN public.page_centroids b 
    ON b.page_url > a.page_url
WHERE (a.centroid_embedding <=> b.centroid_embedding) < 0.05;

COMMIT;

